/**
 * Function to calculate the nth number in the sequence using recursion.
 * 
 * @param n The position of the number to calculate.
 * @return The nth number in the sequence.
 */
int sequence(int n) {
    // Base cases
    if (n <= 0) {
        return 0;
    } else if (n == 1) {
        return 0; // First number in the sequence
    } else if (n == 2) {
        return -1; // Second number in the sequence
